def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    part = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    priority += part * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.2)) ** 2
        elif 5 < ratio <= 8:
            for c in range(2, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 4):
                    val = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.8)
                    priority += np.tanh(val) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3.5
        elif 2.5 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2.5) ** e) / (e * 2.2) * np.sin(e * ratio * 1.3)
            priority = (s * np.sin(9 * ratio * 0.8)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2.1
        elif 1.0 <= ratio < 2.5:
            s = 0
            for f in range(1, 12):
                s += ((2.5 - ratio) ** f) / (f ** 2 + 1.5)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5.1
            else:
                penalty = np.cos(25 * ratio) * 3.7
            priority = s + penalty + np.exp(-2.2 / (ratio + 0.07))
            for g in range(1, 6):
                priority += np.cos(g * ratio * i * 0.9) * ((ratio - 1.0) ** g) / (g * 0.9)
        elif 0.4 <= ratio < 1.0:
            s = 0
            for h in range(1, 18):
                s += ((1.0 - ratio) ** h) / (h * 3.5)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 3)
            for j in range(1, 8):
                priority += ((1.0 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 18):
                s += ((0.4 - ratio) ** k) / (k * 3.8) * np.sin(k * ratio * 2.5)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.3
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.8) * 4.5
            for l in range(1, 9):
                priority += ((0.4 - ratio) ** l) / (l * 8) * np.sin(item * l * 1.3)
        else:
            s = 0
            for m in range(1, 14):
                s += ((0.15 - ratio) ** m) / (m * 6) * np.cos(m * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.3) * 5.7
            for n in range(1, 12):
                priority += ((0.15 - ratio) ** n) / (n * 9) * np.sin(item * n * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.3
        elif bin_cap > item * 3.0:
            priority -= np.exp(-3.5 * ratio) * 5.7
        for o in range(1, 6):
            if (i + o) % 4 == 0:
                priority += np.sin(ratio * (i + o) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + o) * 1.4) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
